// Extract job IDs from WTTJ email by parsing HTML and following SendGrid redirects
const data = $input.first()?.json || {};
const dateReceived = new Date().toISOString().split('T')[0];

// Recursively search for text/html part in multipart messages
function findHtmlPart(parts) {
  if (!parts || !parts.length) return null;
  for (const part of parts) {
    if (part.mimeType === 'text/html' && part.body?.data) {
      return part.body.data;
    }
    // Recurse into nested multipart (e.g. multipart/alternative inside multipart/mixed)
    if (part.parts) {
      const found = findHtmlPart(part.parts);
      if (found) return found;
    }
  }
  return null;
}

// Try multiple ways to get HTML body from Gmail node output
let html = '';

// simple:true output (v2+)
if (data.textHtml) {
  html = data.textHtml;
}
// simple:false output — base64 in payload.parts or payload.body (recursive)
// Gmail API uses URL-safe base64 (- and _ instead of + and /), use 'base64url'
else if (data.payload) {
  const b64 = findHtmlPart(data.payload.parts || []);
  if (b64) {
    html = Buffer.from(b64, 'base64url').toString('utf8');
  }
  // Fallback: single-part message
  if (!html && data.payload.body?.data) {
    html = Buffer.from(data.payload.body.data, 'base64url').toString('utf8');
  }
}
// Direct html field
else if (data.html) {
  html = data.html;
}

console.log(`Gmail output keys: ${Object.keys(data).join(', ')}`);
console.log(`HTML body length: ${html.length}`);
if (data.payload) {
  const topParts = (data.payload.parts || []).map(p => p.mimeType);
  console.log(`Payload mimeType: ${data.payload.mimeType}, parts: [${topParts.join(', ')}]`);
}

if (!html) {
  console.log('No HTML body found in email');
  return [{ json: { _skip: true } }];
}

// Extract URLs from <a href> tags that wrap greyHover blocks (WTTJ job card pattern)
// The job link <a href> precedes the <tbody class="greyHover"> it wraps — NOT inside it
const linkPattern = /<a[^>]+href="(https?:\/\/[^"]+)"[^>]*>/gi;
const seenUrls = new Set();
const urls = [];
let m;
while ((m = linkPattern.exec(html)) !== null) {
  const url = m[1].replace(/&amp;/g, '&');
  if (seenUrls.has(url)) continue;
  const after = html.slice(m.index, m.index + 2000);
  if (/class="greyHover"/.test(after)) {
    seenUrls.add(url);
    urls.push(url);
  }
}

if (urls.length === 0) {
  console.log('No job links found in email HTML');
  return [{ json: { _skip: true } }];
}

console.log(`Found ${urls.length} job link(s) in email, resolving redirects...`);

const items = [];
for (const url of urls) {
  try {
    let currentUrl = url;
    for (let hop = 0; hop < 5; hop++) {
      const res = await fetch(currentUrl, { redirect: 'manual' });
      const location = res.headers.get('location');
      if (!location) break;
      currentUrl = location;
      if (/\/jobs\//.test(currentUrl)) break;
    }
    const idMatch = currentUrl.match(/\/jobs\/([^/?#]+)/);
    if (idMatch) {
      items.push({ json: { _isNew: true, externalId: idMatch[1], source: 'email', dateReceived } });
      console.log(`  \u2192 ${idMatch[1]}`);
    } else {
      console.log(`  \u2192 Could not extract ID from: ${currentUrl}`);
    }
  } catch (e) {
    console.log(`  \u2192 Error: ${e.message}`);
  }
}

return items.length > 0 ? items : [{ json: { _skip: true } }];

// Extract job IDs from JobRecommendations GraphQL response
const json = $input.first().json;
const dateReceived = new Date().toISOString().split('T')[0];

const currentUser = json.data?.currentUser;
if (!currentUser) {
  console.log('Auth expired or invalid response');
  return [{ json: {
    _isNew: true, _error: true, externalId: '__AUTH_EXPIRED__',
    'Date Received': dateReceived,
    'Company': '\u26a0 AUTH EXPIRED',
    'Job Title': 'WTTJ session cookies need refresh \u2014 run: npm run reauth',
    'URL': '', 'Location': '', 'Remote': '', 'Salary': '',
    'Experience': '', 'Technologies': '', 'Function': '',
    'Company Size': '', 'Funding': '',
    'Status': 'AUTH_EXPIRED', 'Source': 'graphql',
    'Job ID': '', 'Apply URL': '', 'Progress': '', 'Applied': ''
  } }];
}

const recs = currentUser.jobRecommendations || [];
if (recs.length === 0) {
  console.log('No recommendations returned');
  return [{ json: { _skip: true } }];
}

const items = recs.map(rec => ({
  json: {
    _isNew: true,
    externalId: rec.job.externalId,
    company: rec.job.company?.name || '',
    title: rec.job.title || '',
    source: 'recommendations',
    dateReceived
  }
}));

console.log(`Extracted ${items.length} recommendation(s)`);
return items;

// Deduplicate job IDs from email + recommendations, filter out skip markers
const allItems = $input.all();
const seen = new Set();
const output = [];

for (const item of allItems) {
  if (item.json._skip) continue;

  // Pass through error items unchanged
  if (item.json._error) {
    output.push(item);
    continue;
  }

  const id = item.json.externalId;
  if (!id || seen.has(id)) {
    if (id) console.log(`  Dedup: skipping duplicate ${id}`);
    continue;
  }
  seen.add(id);
  output.push(item);
}

if (output.length === 0) {
  const dateReceived = new Date().toISOString().split('T')[0];
  console.log('No job IDs after dedup');
  return [{ json: {
    _isNew: true, _error: true,
    'Date Received': dateReceived,
    'Company': '\u26a0 NO JOBS FOUND',
    'Job Title': 'Neither email parsing nor recommendations returned results',
    'URL': '', 'Location': '', 'Remote': '', 'Salary': '',
    'Experience': '', 'Technologies': '', 'Function': '',
    'Company Size': '', 'Funding': '',
    'Status': 'Error', 'Source': 'hybrid',
    'Job ID': '', 'Apply URL': '', 'Progress': '', 'Applied': ''
  } }];
}

console.log(`Dedup: ${allItems.length} input \u2192 ${output.length} unique job(s)`);
return output;

// Parse job details and classify — adds _isNew marker for dedup
const DMV_KEYWORDS = ['washington', 'dc', 'd.c.', 'district of columbia', 'maryland', 'virginia', 'arlington', 'alexandria', 'fairfax', 'reston', 'tysons', 'mclean', 'herndon', 'sterling', 'ashburn', 'leesburg', 'bethesda', 'rockville', 'silver spring', 'college park', 'columbia', 'baltimore', 'annapolis', 'dmv'];
const REMOTE_KEYWORDS = ['remote', 'full remote', 'full-remote', 'fully remote', 'work from home', 'wfh', 'anywhere', 'distributed'];

function classifyLocation(locationStr, isRemote) {
  if (isRemote) return 'Relevant';
  if (!locationStr) return 'Skip';
  const loc = locationStr.toLowerCase();
  for (const kw of REMOTE_KEYWORDS) { if (loc.includes(kw)) return 'Relevant'; }
  for (const kw of DMV_KEYWORDS) { if (loc.includes(kw)) return 'Relevant'; }
  return 'Skip';
}

const items = [];
const dateReceived = new Date().toISOString().split('T')[0];
const dedupItems = $('Dedup & Filter').all();

for (let i = 0; i < $input.all().length; i++) {
  const dedupItem = dedupItems[i]?.json || {};

  if (dedupItem._error) {
    const { _error, _isNew, externalId, ...rest } = dedupItem;
    items.push({ json: { _isNew: true, ...rest, 'Job ID': '', 'Apply URL': '', 'Progress': '', 'Applied': '' } });
    continue;
  }

  const json = $input.all()[i].json;
  const job = json.data?.publicJob;

  if (!job) {
    const errorMsg = json.errors ? json.errors.map(e => e.message).join('; ') : 'Job not found';
    items.push({ json: { _isNew: true, 'Date Received': dateReceived, 'Company': dedupItem.company || '\u26a0 FETCH ERROR', 'Job Title': dedupItem.title || errorMsg, 'URL': '', 'Location': '', 'Remote': '', 'Salary': '', 'Experience': '', 'Technologies': '', 'Function': '', 'Company Size': '', 'Funding': '', 'Status': 'Error', 'Source': dedupItem.source || 'hybrid', 'Job ID': '', 'Apply URL': '', 'Progress': '', 'Applied': '' } });
    continue;
  }

  let salary = '';
  if (job.salaryRange) {
    const { minAmount, maxAmount, currency } = job.salaryRange;
    const fmt = (n) => { const num = parseInt(n); return num >= 1000 ? `${Math.round(num / 1000)}K` : num; };
    if (minAmount && maxAmount) salary = `${currency} ${fmt(minAmount)}\u2013${fmt(maxAmount)}`;
    else if (minAmount) salary = `${currency} ${fmt(minAmount)}+`;
    else if (maxAmount) salary = `Up to ${currency} ${fmt(maxAmount)}`;
  }

  const locations = (job.formattedLocationPreferences || []).map(l => l.name).join(', ');
  let experience = '';
  if (job.minYearsExperienceRequired != null && job.maxYearsExperienceRequired != null) experience = `${job.minYearsExperienceRequired}\u2013${job.maxYearsExperienceRequired} years`;
  else if (job.minYearsExperienceRequired != null) experience = `${job.minYearsExperienceRequired}+ years`;
  else if (job.maxYearsExperienceRequired != null) experience = `Up to ${job.maxYearsExperienceRequired} years`;

  const technologies = (job.technologiesUsed || []).map(t => t.value).join(', ');
  const co = job.company || {};
  const companySize = co.size?.value || '';
  const funding = co.totalFunding ? `${co.totalFunding.currency} ${Math.round(parseInt(co.totalFunding.amount) / 1000000)}M` : '';
  const remote = job.remoteOnly ? 'Yes' : 'No';
  const status = classifyLocation(locations, job.remoteOnly);
  const url = `https://app.welcometothejungle.com/jobs/${job.externalId}`;
  const source = dedupItem.source || 'hybrid';

  items.push({ json: { _isNew: true, 'Date Received': dateReceived, 'Company': co.name || '', 'Job Title': job.title || '', 'URL': url, 'Location': locations, 'Remote': remote, 'Salary': salary, 'Experience': experience, 'Technologies': technologies, 'Function': [job.function?.value, job.subFunction?.value].filter(Boolean).join(' \u2192 '), 'Company Size': companySize, 'Funding': funding, 'Status': status, 'Source': source, 'Job ID': job.externalId, 'Apply URL': job.originalUrl || '', 'Progress': 'new', 'Applied': '' } });
}

if (items.length === 0) {
  items.push({ json: { _isNew: true, 'Date Received': dateReceived, 'Company': '\u26a0 NO JOBS PROCESSED', 'Job Title': 'All job detail fetches failed', 'URL': '', 'Location': '', 'Remote': '', 'Salary': '', 'Experience': '', 'Technologies': '', 'Function': '', 'Company Size': '', 'Funding': '', 'Status': 'Error', 'Source': 'hybrid', 'Job ID': '', 'Apply URL': '', 'Progress': '', 'Applied': '' } });
}

return items;

// Dedup using $input.all() — no cross-branch $('NodeName') references
// Items from Parse & Classify have _isNew: true, existing sheet rows do not
// Use String() to handle numeric values from Google Sheets (e.g. USAJobs IDs)
const allItems = $input.all();

const newItems = [];
const existingJobIds = new Set();
const existingUrls = new Set();

// First pass: separate existing rows from new items
for (const item of allItems) {
  if (item.json._isNew) {
    newItems.push(item);
  } else {
    const jobId = String(item.json['Job ID'] ?? '').trim();
    const url = String(item.json['URL'] ?? '').trim();
    if (jobId) existingJobIds.add(jobId);
    if (url) existingUrls.add(url);
  }
}

console.log(`Dedup: ${newItems.length} new items, ${existingJobIds.size} existing Job IDs, ${existingUrls.size} existing URLs`);

// Second pass: filter new items against existing + within-batch dedup
const output = [];
let skippedCount = 0;
const batchJobIds = new Set();

for (const item of newItems) {
  const jobId = String(item.json['Job ID'] ?? '').trim();
  const url = String(item.json['URL'] ?? '').trim();
  const status = item.json['Status'] || '';

  // Always pass through error items
  if (status === 'AUTH_EXPIRED' || status === 'Error') {
    const { _isNew, _error, ...rest } = item.json;
    output.push({ json: rest });
    continue;
  }

  // Dedup by Job ID (primary) or URL (fallback)
  if (jobId && (existingJobIds.has(jobId) || batchJobIds.has(jobId))) { skippedCount++; continue; }
  if (!jobId && url && existingUrls.has(url)) { skippedCount++; continue; }

  if (jobId) batchJobIds.add(jobId);

  // Remove _isNew marker before appending to sheet
  const { _isNew, ...rest } = item.json;
  output.push({ json: rest });
}

console.log(`Dedup: skipped ${skippedCount} duplicate(s), passing ${output.length} new item(s)`);

if (output.length > 0) return output;

// No new jobs — emit at most one heartbeat row per calendar day
const today = new Date().toISOString().split('T')[0];
const alreadyHasHeartbeat = allItems.some(item =>
  !item.json._isNew &&
  String(item.json['Status'] ?? '') === 'Skip' &&
  String(item.json['Company'] ?? '') === '✓ No new jobs — WTTJ' &&
  String(item.json['Date Received'] ?? '').startsWith(today)
);

if (alreadyHasHeartbeat) return [];

return [{
  json: {
    'Date Received': today,
    'Company': '✓ No new jobs — WTTJ',
    'Job Title': 'Workflow ran — all recommendations already tracked',
    'URL': '',
    'Location': '',
    'Remote': '',
    'Salary': '',
    'Experience': '',
    'Technologies': '',
    'Function': '',
    'Company Size': '',
    'Funding': '',
    'Status': 'Skip',
    'Source': 'hybrid',
    'Job ID': '',
    'Apply URL': '',
    'Progress': '',
    'Applied': ''
  }
}];
